/** 与网关/库字段大小写兼容 */
function isFeedVideoType(t) {
  return String(t || '').toLowerCase() === 'video'
}

/** 放宽校验：COS 部分链接无后缀，只要 https 且明显不是静态图即可 */
function isUsableRemoteVideoUrl(url) {
  if (!url || typeof url !== 'string') return false
  const u = url.trim()
  if (!/^https?:\/\//i.test(u)) return false
  const path = u.split('?')[0].toLowerCase()
  if (/\.(jpg|jpeg|png|gif|webp|bmp|svg)$/i.test(path)) return false
  return true
}

