  async onReachBottomList() {
    if (this.data.loadingMore || this._loadingMoreLock || !this.data.hasMoreCloud) return

    const reachBottomStart = Date.now()
    this._loadingMoreLock = true
    this.setData({ loadingMore: true })

    try {
      const mediaResult = await this.fetchCloudMedia(this.data.nextOffset, PAGE_SIZE)

      if (!mediaResult.items.length) {
        this.setData({
          nextOffset: mediaResult.nextOffset,
          hasMoreCloud: mediaResult.hasMore,
          loadingMore: false,
          endBounce: false
        })

        return
      }

      const incomingItems = mediaResult.items
      const mediaList = this.data.mediaList.concat(incomingItems)
      const merged = injectShopCards(mediaList, this.data.shopList, SHOP_INSERT_EVERY)
      const { leftColumn, rightColumn } = this.buildWaterfallColumns(merged)

      this.setData({
        mediaList,
        nextOffset: mediaResult.nextOffset,
        hasMoreCloud: mediaResult.hasMore,
        leftColumn,
        rightColumn,
        loadingMore: false,
        endBounce: false
      })

    } catch (error) {
      this.setData({ loadingMore: false, endBounce: false })
      wx.showToast({ title: '加载失败，请稍后重试', icon: 'none' })
    } finally {
      this._loadingMoreLock = false
    }
  },

